payload.raw:
{
  "layout": "timeline",
  "title": "创新设计",
  "events": [
    {
      "date": "第1–2月",
      "title": "硬件攻坚阶段",
      "description": "完成柔性传感器微结构设计、液态金属-聚氨酯复合材料制备与信号标定；构建仿水膜-鱼网拓扑传感阵列，实现0.1mm级空间分辨率。配置硬件工程师2名、材料研究员1名，依托柔性材料合成设备与高精度信号采集平台。"
    },
    {
      "date": "第3月",
      "title": "算法开发阶段",
      "description": "开发分层CNN-LSTM手势识别模型，集成时序滑动窗口分割与噪声抑制模块，实测识别准确率>98.2%；构建多模态融合协议栈，开发效率提升60%。配置算法工程师3名、数据标注员1名，使用4×A100 GPU服务器与仿真环境。"
    },
    {
      "date": "第4月",
      "title": "系统集成阶段",
      "description": "软硬件联调，嵌入微型电磁致动器阵列与半导体温控模块，实现压力/温度微秒级精准调控；构建感知-意图-反馈闭环系统。配置全栈工程师2名、测试工程师2名，对接H-Box全息舱、李未可眼镜等合作设备接口。"
    },
    {
      "date": "第5–6月",
      "title": "场景验证优化阶段",
      "description": "在工业远程操控、虚拟实训等多场景开展压力测试与用户体验迭代；验证高鲁棒手势识别、触觉反馈质感及跨设备部署能力，形成可复用交互标准接口，完成关键技术体系原型验证，具备工程化落地基础。"
    }
  ]
}

